/* LSS的个人博客 - 完整样式文件 */

/* 重置和基础样式 */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;
    line-height: 1.6;
    color: #333;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    margin: 0;
    padding: 0;
}

/* 头部样式 */
.header {
    background: rgba(255, 255, 255, 0.95);
    backdrop-filter: blur(10px);
    padding: 20px;
    text-align: center;
    border-bottom: 2px solid #e1e5e9;
}

.header h1 {
    color: white;
    font-size: 2.5rem;
    margin: 0;
    font-weight: 600;
}

/* 导航样式 */
.nav {
    background: white;
    padding: 15px 30px;
    box-shadow: 0 4px 20px rgba(0,0,0,0.1);
    max-width: 1200px;
    margin: 0 auto;
}

.nav a {
    display: inline-block;
    padding: 10px 20px;
    margin: 5px;
    background: #f8f9fa;
    color: #333;
    text-decoration: none;
    border-radius: 25px;
    transition: all 0.3s;
}

.nav a:hover {
    background: #e9ecef;
    color: white;
    transform: translateY(-2px);
}

/* 内容区域 */
.content {
    max-width: 1200px;
    margin: 30px auto;
    padding: 40px;
    background: white;
    border-radius: 15px;
    box-shadow: 0 10px 30px rgba(0,0,0,0.1);
}

.card {
    background: white;
    padding: 30px;
    border-radius: 12px;
    box-shadow: 0 4px 15px rgba(0,0,0,0.1);
    margin-bottom: 25px;
    transition: transform 0.3s;
}

.card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(0,0,0,0.15);
}

/* 响应式设计 */
@media (max-width: 768px) {
    .nav {
        padding: 15px;
        flex-direction: column;
    }

    .nav a {
        margin: 3px 0;
        width: 100%;
        text-align: center;
    }

    .content {
        margin: 20px 15px;
        padding: 25px;
    }
}

/* 动画效果 */
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}

.fade-in {
    animation: fadeIn 0.6s ease-out;
}

/* 页面特定样式 */
.home-page {
    text-align: center;
    padding: 60px 20px;
}

.home-page h1 {
    font-size: 3rem;
    color: #2c3e50;
    margin-bottom: 30px;
}

.status-success {
    background: #d4edda;
    color: white;
    padding: 15px 25px;
    border-radius: 8px;
    margin: 10px 0;
    border-left: 4px solid #4CAF50;
}

.status-loading {
    background: #fff3cd;
    color: #856404;
    padding: 15px 25px;
    border-radius: 8px;
    margin: 10px 0;
    border-left: 4px solid #ff9800;
}

/* 按钮和交互 */
.btn {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    padding: 12px 25px;
    border-radius: 8px;
    cursor: pointer;
    font-weight: 600;
    transition: all 0.3s;
}

.btn:hover {
    background: linear-gradient(135deg, #764ba2 0%, #4c63d2 100%);
    transform: scale(1.05);
}

/* 页脚 */
.footer {
    background: #f8f9fa;
    color: #6c757d;
    text-align: center;
    padding: 25px;
    border-top: 2px solid #e9ecef;
    margin-top: 50px;
}

